section.script:

(function () {
    function initBrochureEsriMaps() {
        if (typeof L === 'undefined') {
            setTimeout(initBrochureEsriMaps, 300);
            return;
        }

        var maps = document.querySelectorAll('.o_property_brochure_esri_map:not([data-map-ready="1"])');
        maps.forEach(function (el) {
            var lat = parseFloat(el.dataset.latitude || '');
            var lng = parseFloat(el.dataset.longitude || '');
            var title = el.dataset.title || 'Localisation du bien';

            if (isNaN(lat) || isNaN(lng)) {
                return;
            }

            el.dataset.mapReady = '1';

            var map = L.map(el, {
                scrollWheelZoom: false,
                dragging: true,
            }).setView([lat, lng], 17);

            L.tileLayer('https://server.arcgisonline.com/ArcGIS/rest/services/World_Imagery/MapServer/tile/{z}/{y}/{x}', {
                maxZoom: 19,
                attribution: 'Tiles © Esri',
            }).addTo(map);

            L.marker([lat, lng]).addTo(map).bindPopup(title);

            setTimeout(function () {
                map.invalidateSize();
            }, 500);
        });
    }

    if (document.readyState === 'loading') {
        document.addEventListener('DOMContentLoaded', initBrochureEsriMaps);
    } else {
        initBrochureEsriMaps();
    }
    window.addEventListener('load', initBrochureEsriMaps);
})();
